class Solution {
    calculateWaysToClimb(totalSteps) {
        // Base cases
        if (totalSteps === 1) return 1;
        if (totalSteps === 2) return 2;

        const dp = new Array(totalSteps + 1).fill(0);
        dp[1] = 1;
        dp[2] = 2;

        // Fill DP table
        for (let i = 3; i <= totalSteps; i++) {
            dp[i] = dp[i - 1] + dp[i - 2];
        }

        return dp[totalSteps];
    }
}
